{"code": "from hermes_tools import terminal

# Deep scan the entire nexa-paraguay repo structure
result = terminal("cd /root/nexa-paraguay && find . -maxdepth 3 -not -path './node_modules/*' -not -path './.git/*' -not -path './.next/*' -not -path './dist/*' -type f | sort", timeout=5)
files = result['output'].strip().split('\n')
print(f"Total files: {len(files)}")
print()

# Group by directory
dirs = {}
for f in files:
    parts = f.split('/')
    top = parts[1] if len(parts) > 1 else '(root)'
    if top not in dirs:
        dirs[top] = []
    dirs[top].append(f)

for d, flist in sorted(dirs.items()):
    ext_counts = {}
    for f in flist:
        ext = f.split('.')[-1] if '.' in f else '(no ext)'
        ext_counts[ext] = ext_counts.get(ext, 0) + 1
    exts = ', '.join([f"{k}: {v}" for k,v in sorted(ext_counts.items())])
    print(f"{d:25s} ({len(flist):3d} files) — {exts}")
"}

