{"content": "/**
 * Web Vitals monitoring — sends CLS, LCP, INP to GA4
 * 
 * Usage: import this file in layout.tsx or any client component:
 *   import './lib/web-vitals'
 *   <WebVitals />
 */

'use client';

import { useEffect } from 'react';
import { onCLS, onLCP, onINP, onFCP, onTTFB } from 'web-vitals';

function sendToGA4(metric: any) {
  const { name, value, rating, delta, id, navigationType } = metric;
  const body = {
    event: 'web_vital',
    event_category: 'Web Vitals',
    event_label: id,
    value: Math.round(name === 'CLS' ? value * 1000 : value),
    non_interaction: true,
    metric_name: name,
    metric_value: value,
    metric_rating: rating,
    metric_delta: delta,
    navigation_type: navigationType,
    page_path: window.location.pathname,
    page_locale: window.location.pathname.split('/')[1] || 'es',
  };

  // Send to GA4 if available
  if (typeof window !== 'undefined' && (window as any).gtag) {
    (window as any).gtag('event', 'web_vital', body);
  }

  // Also log to console in development
  if (process.env.NODE_ENV === 'development') {
    console.log(`[Web Vitals] ${name}: ${rating} (${Math.round(value)}${name === 'CLS' ? '' : 'ms'})`);
  }
}

export function WebVitals() {
  useEffect(() => {
    onCLS(sendToGA4);
    onFCP(sendToGA4);
    onLCP(sendToGA4);
    onINP(sendToGA4);
    onTTFB(sendToGA4);
  }, []);

  return null;
}
